package templates

// Field describes a form field for a protocol template.
type Field struct {
	Name        string   `json:"name"`
	Label       string   `json:"label"`
	Type        string   `json:"type"` // string|int|bool|select|password
	Required    bool     `json:"required"`
	Default     any      `json:"default,omitempty"`
	Options     []string `json:"options,omitempty"`
	Description string   `json:"description,omitempty"`
}

// Template is a built-in inbound protocol form schema.
// Secret fields (password, uuid, TLS keys, Reality keys) are NOT exposed here —
// they are auto-generated by inboundfill on create.
type Template struct {
	ID       string  `json:"id"`
	Protocol string  `json:"protocol"`
	Name     string  `json:"name"`
	Fields   []Field `json:"fields"`
}

